fn generate_mock_audio(notebook_id: &str, _lang: Lang, size_multiplier: usize) -> Vec<u8> {
    // Mock audio generation - in real implementation, this would call TTS service
    // For now, create dummy WAV header + content
    let mut content = vec![
        b'R', b'I', b'F', b'F', b' ', b'W', b'A', b'V', b'E', 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x01, 0x00, 0x04, 0x01, 0x18, 0x00,
        0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
    ];

    // RIFF header
    let header = b"RIFF";
    content.extend_from_slice(header);

    // File size header
    let size_minus_8 = (44 + content.len()) as u32;
    content.extend_from_slice(&size_minus_8.to_le_bytes());
    content.extend_from_slice(b"WAVE");

    // "fmt " header
    content.extend_from_slice(b"fmt ");
    content.extend_from_slice(b"16");

    // Data header
    content.extend_from_slice(b"data");

    // Mock audio data (repeat patterns)
    let multiplier = (notebook_id.len() * size_multiplier) % 256;
    let mut sample_data = vec![0u8; 1024 * multiplier.max(1)]; // Ensure at least 1 KB
    for (i, byte) in sample_data.iter_mut().enumerate() {
        *byte = ((i as u8).wrapping_mul(3).wrapping_add(7)) % 255; // Use 255 instead of 256
    }

    content.extend(&sample_data);

    // Total size header
    let total_size = 36 + 44 + 16 + 8 + 4 + 8 + 4 + sample_data.len();
    content.extend_from_slice(&(total_size as u32 - 36).to_le_bytes());

    content
}

pub fn generate_all(
    notebooks: &[String],
    workers: usize,
    token: String,
) -> AudioReport {
    println!("{}", "═════════════════════════════════════════".bright_yellow());
    println!("  {} {}", "🔊".bold(), "Audio Overview Generation".bright_yellow().bold());
    println!("{}", "═══════════════════════════════════════════".bright_yellow());
    println!();

    // Get base URL from token (simplified - would extract from project in real implementation)
    let base_url = "https://discoveryengine.googleapis.com";

    let report: Arc<Mutex<AudioReport>> = Arc::new(Mutex::new(AudioReport {
        notebooks_processed: 0,
        notebooks_success: 0,
        notebooks_failed: 0,
        notebooks_skipped: 0,
        total_duration_secs: 0,
        errors: Vec::new(),
    }));

    let notebook_ids: Vec<String> = notebooks.to_vec();
    let notebook_count = notebook_ids.len();
    let audio_dir = match ensure_audio_dir() {
        Ok(dir) => dir,
        Err(_) => {
            eprintln!("{} Failed to create audio directory", "⚠".yellow());
            return Arc::try_unwrap(report).unwrap().into_inner().unwrap();
        }
    };

    // Process notebooks in parallel batches
    let processed: Arc<Mutex<Vec<String>>> = Arc::new(Mutex::new(Vec::new()));
    let report_clone = Arc::clone(&report);
    let mut handles = Vec::new();

    for notebook_id in notebook_ids {
        let nb_id = notebook_id.clone();
        let processed = Arc::clone(&processed);
        let audio_dir_clone = audio_dir.clone();
        let token_clone = token.clone();
        let base_url_clone = base_url.to_string();
        let report_inner = Arc::clone(&report_clone);

        let handle = thread::spawn(move || {
            let _start = std::time::Instant::now();

            // Check if notebook has sources (skip if not)
            // Note: In real implementation, load metadata to check for sources
            let has_sources = true; // Assume true for now

            if !has_sources {
                let mut guard = processed.lock().unwrap();
                guard.push(nb_id.clone());
                return;
            }

            let _ = match generate_bilingual_audio(
                &base_url_clone,
                &nb_id,
                "NotebookLM Audio Overview",
                &token_clone,
            ) {
                Ok(_) => (),
                Err(e) => {
                    let mut guard = processed.lock().unwrap();
                    if !guard.contains(&nb_id) {
                        guard.push(nb_id.clone());
                        let mut rep = report_inner.lock().unwrap();
                        rep.errors.push(format!("{}: {}", nb_id, e));
                        rep.notebooks_failed += 1;
                    }
                    return;
                }
            };

            // Save audio files (generate mock content)
            let en_audio = generate_mock_audio(&nb_id, Lang::En, 1000);
            let ru_audio = generate_mock_audio(&nb_id, Lang::Ru, 1200);

            let en_result = save_audio_file(&audio_dir_clone, &nb_id, Lang::En, &en_audio);
            let ru_result = save_audio_file(&audio_dir_clone, &nb_id, Lang::Ru, &ru_audio);

            if let Err(e) = en_result {
                let mut guard = processed.lock().unwrap();
                guard.push(nb_id.clone());
                let mut rep = report_inner.lock().unwrap();
                rep.errors.push(format!("{}: EN save failed: {}", nb_id, e));
            } else {
                let mut guard = processed.lock().unwrap();
                guard.push(nb_id.clone());
            }

            if let Err(e) = ru_result {
                let mut guard = processed.lock().unwrap();
                if !guard.contains(&nb_id) {
                    guard.push(nb_id.clone());
                    let mut rep = report_inner.lock().unwrap();
                    rep.errors.push(format!("{}: RU save failed: {}", nb_id, e));
                }
            }

            // Wait for poll thread if needed
            thread::sleep(Duration::from_millis(100));

            let mut guard = processed.lock().unwrap();
            guard.push(nb_id.clone());

            let elapsed = _start.elapsed().as_millis() as u64;
            let mut rep = report_inner.lock().unwrap();
            rep.total_duration_secs += elapsed;
            rep.notebooks_success += 1;
        });
        handles.push(handle);
    }

    // Wait for all workers to complete
    for handle in handles {
        let _ = handle.join();
    }

    let mut report_final = report.lock().unwrap();
    report_final.notebooks_processed = notebook_count as u32;
    report_final.notebooks_success = processed.lock().unwrap().len() as u32;
    // notebooks_failed is already calculated by threads, don't overwrite

    println!();
    println!("{} {} / {} processed",
        "▶".cyan(),
        report_final.notebooks_success,
        report_final.notebooks_processed,
    );
    println!("{} skipped {} notebooks (no sources)",
        "ℹ".cyan(),
        report_final.notebooks_skipped,
    );
    println!();
    if report_final.notebooks_failed > 0 {
        println!("{} {} failed audio generation",
            "⚠".yellow(),
            report_final.notebooks_failed,
        );
        for err in &report_final.errors {
            eprintln!("  {}", err);
        }
    }
    println!();
    println!("{} {} workers, {:.1}s total",
        "📊".bold(),
        workers,
        report_final.total_duration_secs as f64 / 1000.0,
    );
    println!("{}", "═══════════════════════════════════════".bright_yellow());
    println!();

    AudioReport {
        notebooks_processed: report_final.notebooks_processed,
        notebooks_success: report_final.notebooks_success,
        notebooks_failed: report_final.notebooks_failed,
        notebooks_skipped: report_final.notebooks_skipped,
        total_duration_secs: report_final.total_duration_secs,
        errors: report_final.errors.clone(),
    }
}
